#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Draft,
    Review,
    Approved,
    Rejected,
    Archived,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Approve,
    Reject,
    Revise,
    Archive,
    Restore,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::Draft;

    for event in events {
        status = match (status, event) {
            (Status::Draft, Event::Submit) => Status::Review,
            (Status::Draft, Event::Archive) => Status::Archived,

            (Status::Review, Event::Approve) => Status::Approved,
            (Status::Review, Event::Reject) => Status::Rejected,
            (Status::Review, Event::Archive) => Status::Archived,

            (Status::Rejected, Event::Revise) => Status::Draft,
            (Status::Rejected, Event::Archive) => Status::Archived,

            (Status::Approved, Event::Archive) => Status::Archived,
            (Status::Approved, Event::Revise) => Status::Draft,

            (Status::Archived, Event::Restore) => Status::Draft,

            _ => status,
        };
    }

    status
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event::*, Status::*};

    #[test]
    fn happy_path_reaches_approved() {
        assert_eq!(apply_events(&[Submit, Approve]), Approved);
    }

    #[test]
    fn rejected_items_can_be_revised_and_resubmitted() {
        assert_eq!(apply_events(&[Submit, Reject, Revise, Submit]), Review);
    }

    #[test]
    fn approved_items_require_restore_before_revision() {
        assert_eq!(apply_events(&[Submit, Approve, Revise]), Approved);
        assert_eq!(apply_events(&[Submit, Approve, Archive, Restore, Revise]), Draft);
    }

    #[test]
    fn restore_returns_to_prior_active_state() {
        assert_eq!(apply_events(&[Submit, Archive, Restore]), Review);
        assert_eq!(apply_events(&[Submit, Reject, Archive, Restore]), Rejected);
        assert_eq!(apply_events(&[Archive, Restore]), Draft);
    }

    #[test]
    fn archive_is_terminal_until_restore() {
        assert_eq!(apply_events(&[Submit, Archive, Approve, Reject, Revise]), Archived);
    }

    #[test]
    fn duplicate_submits_do_not_change_review_state() {
        assert_eq!(apply_events(&[Submit, Submit, Approve]), Approved);
    }
}

