use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    Unknown,
    Todo,
    InProgress,
    Blocked,
    Done,
}

#[derive(Default, Debug)]
struct Stats {
    opened: u32,
    closed: u32,
    reopened: u32,
}

#[derive(Debug)]
struct Ticket {
    status: Status,
    stats: Stats,
}

impl Ticket {
    fn new() -> Self {
        Self {
            status: Status::Unknown,
            stats: Stats::default(),
        }
    }
}

fn status_name(s: Status) -> &'static str {
    match s {
        Status::Unknown => "unknown",
        Status::Todo => "todo",
        Status::InProgress => "in_progress",
        Status::Blocked => "blocked",
        Status::Done => "done",
    }
}

fn apply_event(ticket: &mut Ticket, event: &str) {
    match event {
        "create" => {
            ticket.status = Status::Todo;
            ticket.stats.opened += 1;
        }
        "start" => {
            ticket.status = Status::InProgress;
        }
        "block" => {
            ticket.status = Status::Blocked;
        }
        "resume" => {
            ticket.status = Status::InProgress;
        }
        "close" => {
            ticket.status = Status::Done;
            ticket.stats.closed += 1;
        }
        "reopen" => {
            ticket.status = Status::Todo;
            ticket.stats.reopened += 1;
        }
        _ => {}
    }
}

fn main() {
    let events = [
        ("u1", "create"),
        ("u1", "start"),
        ("u1", "close"),
        ("u1", "reopen"),
        ("u1", "start"),
        ("u1", "close"),
        ("u2", "start"),
        ("u2", "create"),
        ("u2", "start"),
        ("u3", "create"),
        ("u3", "block"),
        ("u3", "resume"),
        ("u3", "block"),
        ("u4", "close"),
        ("u4", "reopen"),
    ];

    let mut tickets: BTreeMap<&str, Ticket> = BTreeMap::new();
    for (id, event) in events {
        let ticket = tickets.entry(id).or_insert_with(Ticket::new);
        apply_event(ticket, event);
    }

    for id in ["u1", "u2", "u3", "u4"] {
        let ticket = tickets.get(id).unwrap();
        println!(
            "{}: {} (opened={}, closed={}, reopened={})",
            id,
            status_name(ticket.status),
            ticket.stats.opened,
            ticket.stats.closed,
            ticket.stats.reopened
        );
    }
}

