fn is_valid(line: &str) -> bool {
    let mut parts = line.split('|');
    let name = parts.next().unwrap_or("");
    let age = parts.next().unwrap_or("");
    let city = parts.next().unwrap_or("");

    if parts.next().is_some() {
        return false;
    }

    if name.is_empty() || city.is_empty() {
        return false;
    }

    age.parse::<u8>().is_ok()
}

fn main() {
    let input = "alice|30|Paris\nbob||Rome\n|22|Berlin\ncarol|x|Oslo\ndave|44|";
    let count = input.lines().filter(|line| is_valid(line)).count();
    println!("valid={}", count);
}

