use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Order<'a> {
    pub region: &'a str,
    pub amount_cents: i64,
    pub refunded: bool,
}

pub fn build_report(orders: &[Order<'_>]) -> String {
    let mut totals: BTreeMap<&str, i64> = BTreeMap::new();
    let mut order_counts: BTreeMap<&str, usize> = BTreeMap::new();

    for order in orders {
        *totals.entry(order.region).or_insert(0) += order.amount_cents;
        *order_counts.entry(order.region).or_insert(0) += 1;
    }

    let mut out = String::new();
    for (region, total) in totals {
        let count = order_counts.get(region).copied().unwrap_or(0);
        out.push_str(&format!("{}: {} orders, ${:.2}\n", region, count, total as f64 / 100.0));
    }

    if out.is_empty() {
        out.push_str("no sales\n");
    }

    out
}

