#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub host: String,
    pub port: u16,
    pub use_tls: bool,
}

impl Default for Config {
    fn default() -> Self {
        Self {
            host: "localhost".to_string(),
            port: 8080,
            use_tls: false,
        }
    }
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub use_tls: Option<bool>,
}

pub fn merge_config(
    defaults: Config,
    file_cfg: PartialConfig,
    env_cfg: PartialConfig,
    cli_cfg: PartialConfig,
) -> Config {
    let mut merged = defaults;

    if let Some(host) = file_cfg.host {
        merged.host = host;
    }
    if let Some(port) = file_cfg.port {
        merged.port = port;
    }
    if let Some(use_tls) = file_cfg.use_tls {
        merged.use_tls = use_tls;
    }

    if let Some(host) = env_cfg.host {
        merged.host = host;
    }
    if let Some(port) = env_cfg.port {
        merged.port = port;
    }
    if let Some(use_tls) = env_cfg.use_tls {
        merged.use_tls = use_tls;
    }

    if cli_cfg.host.is_some() || cli_cfg.port.is_some() || cli_cfg.use_tls.is_some() {
        merged = Config {
            host: cli_cfg.host.unwrap_or_default(),
            port: cli_cfg.port.unwrap_or_default(),
            use_tls: cli_cfg.use_tls.unwrap_or(false),
        };
    }

    merged
}

#[cfg(test)]
mod tests {
    use super::*;

    fn defaults() -> Config {
        Config::default()
    }

    #[test]
    fn file_then_env_then_cli_precedence_is_respected() {
        let file_cfg = PartialConfig {
            host: Some("file.internal".into()),
            port: Some(7000),
            use_tls: Some(false),
        };
        let env_cfg = PartialConfig {
            host: None,
            port: Some(8000),
            use_tls: Some(true),
        };
        let cli_cfg = PartialConfig {
            host: Some("cli.internal".into()),
            port: None,
            use_tls: None,
        };

        let merged = merge_config(defaults(), file_cfg, env_cfg, cli_cfg);
        assert_eq!(
            merged,
            Config {
                host: "cli.internal".into(),
                port: 8000,
                use_tls: true,
            }
        );
    }

    #[test]
    fn cli_partial_override_keeps_lower_layer_values() {
        let file_cfg = PartialConfig {
            host: Some("file.internal".into()),
            port: Some(7000),
            use_tls: Some(false),
        };
        let env_cfg = PartialConfig {
            host: Some("env.internal".into()),
            port: None,
            use_tls: Some(true),
        };
        let cli_cfg = PartialConfig {
            host: None,
            port: Some(9000),
            use_tls: None,
        };

        let merged = merge_config(defaults(), file_cfg, env_cfg, cli_cfg);
        assert_eq!(merged.host, "env.internal");
        assert_eq!(merged.port, 9000);
