#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum State {
    Draft,
    Open,
    InProgress,
    Blocked,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Start,
    Block,
    Unblock,
    Resolve,
    Reopen,
    Close,
}

pub fn apply_events(events: &[Event]) -> State {
    let mut state = State::Draft;
    for &event in events {
        state = step(state, event);
    }
    state
}

fn step(state: State, event: Event) -> State {
    match event {
        Event::Submit => State::Open,
        Event::Start => State::InProgress,
        Event::Block => State::Blocked,
        Event::Unblock => State::Open,
        Event::Resolve => State::Resolved,
        Event::Reopen => State::Open,
        Event::Close => State::Closed,
    }
}

