pub fn validate_record(line: &str) -> bool {
    let mut id_ok = false;
    let mut name_ok = false;
    let mut score_ok = false;

    for part in line.split(';') {
        let mut kv = part.splitn(2, '=');
        let key = match kv.next() {
            Some(k) => k,
            None => return false,
        };
        let value = match kv.next() {
            Some(v) => v,
            None => return false,
        };

        match key {
            "id" => {
                id_ok = !value.is_empty() && value.chars().all(|c| c.is_ascii_digit());
            }
            "name" => {
                name_ok = !value.is_empty() && value.chars().all(|c| c.is_ascii_alphabetic());
            }
            "score" => {
                score_ok = value.parse::<u8>().map(|n| n <= 100).unwrap_or(false);
            }
            _ => return false,
        }
    }

    id_ok && name_ok && score_ok
}

